// ← 換成你「行銷整合報告」分頁的 gid（看試算表網址 #gid=... 那串數字）
const SHEET_ID = 0;
const gscRows = ($('GSC 查詢').first().json.rows) || [];
const gscClicks = gscRows.reduce((s, r) => s + (r.clicks || 0), 0);
const gscImpr = gscRows.reduce((s, r) => s + (r.impressions || 0), 0);
const gscPos = gscRows.length ? gscRows.reduce((s, r) => s + (r.position || 0), 0) / gscRows.length : 0;
const gaRows = ($('GA4 查詢').first().json.rows) || [];
const gn = (g, i) => Number((g.metricValues && g.metricValues[i]) ? g.metricValues[i].value : 0);
const gaSess = gaRows.reduce((s, g) => s + gn(g, 0), 0);
const gaUsers = gaRows.reduce((s, g) => s + gn(g, 1), 0);
const gaViews = gaRows.reduce((s, g) => s + gn(g, 2), 0);
const th = ($('Threads 粉絲').first().json.data) || [];
const tm = (n) => { const m = th.find((d) => d.name === n); if (!m) return 0; if (m.total_value && m.total_value.value != null) return Number(m.total_value.value); if (Array.isArray(m.values)) return m.values.reduce((s, v) => s + Number(v.value || 0), 0); return 0; };
const followers = tm('followers_count');
const thViews = tm('views');
const thEng = tm('likes') + tm('replies') + tm('reposts') + tm('quotes');
const end = $today.minus({ days: 1 }).toFormat('yyyy-MM-dd');
const start = $today.minus({ days: 7 }).toFormat('yyyy-MM-dd');
const rows = [];
const sec = [], hdr = [], sub = [];
const p = (a, b, c, d) => rows.push([a == null ? '' : a, b == null ? '' : b, c == null ? '' : c, d == null ? '' : d]);
p(`📊 行銷整合週報   ${start} – ${end}`);
p('');
sec.push(rows.length); p('🔍 搜尋成效（Google 搜尋）');
hdr.push(rows.length); p('關鍵字', '點擊', '曝光', '排名');
for (const r of gscRows) p((r.keys && r.keys[0]) || '', r.clicks, r.impressions, r.position != null ? Number(r.position.toFixed(1)) : '');
sub.push(rows.length); p('▸ 小計', gscClicks, gscImpr, Number(gscPos.toFixed(1)));
p('');
sec.push(rows.length); p('🌐 網站流量（GA4）');
hdr.push(rows.length); p('流量來源', '造訪次數', '訪客人數', '瀏覽頁數');
for (const g of gaRows) p((g.dimensionValues && g.dimensionValues[0] ? g.dimensionValues[0].value : ''), gn(g, 0), gn(g, 1), gn(g, 2));
sub.push(rows.length); p('▸ 小計', gaSess, gaUsers, gaViews);
p('');
sec.push(rows.length); p('🧵 Threads（脆）');
hdr.push(rows.length); p('粉絲', '瀏覽', '互動');
p(followers, thViews, thEng);
while (rows.length < 200) p('');
const white = { red: 1, green: 1, blue: 1 };
const grey = { red: 0.93, green: 0.93, blue: 0.93 };
const cols = [{ red: 0.27, green: 0.45, blue: 0.77 }, { red: 0.30, green: 0.60, blue: 0.36 }, { red: 0.50, green: 0.36, blue: 0.66 }];
const band = (i, bg, bold, wht) => ({ repeatCell: { range: { sheetId: SHEET_ID, startRowIndex: i, endRowIndex: i + 1, startColumnIndex: 0, endColumnIndex: 4 }, cell: { userEnteredFormat: { backgroundColor: bg, textFormat: { bold: !!bold, foregroundColor: wht ? { red: 1, green: 1, blue: 1 } : { red: 0.13, green: 0.13, blue: 0.13 } } } }, fields: 'userEnteredFormat(backgroundColor,textFormat)' } });
const req = [];
req.push({ repeatCell: { range: { sheetId: SHEET_ID, startRowIndex: 0, endRowIndex: 200, startColumnIndex: 0, endColumnIndex: 4 }, cell: { userEnteredFormat: { backgroundColor: white, textFormat: { bold: false, foregroundColor: { red: 0.13, green: 0.13, blue: 0.13 } }, horizontalAlignment: 'LEFT' } }, fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment)' } });
req.push({ repeatCell: { range: { sheetId: SHEET_ID, startRowIndex: 1, endRowIndex: 200, startColumnIndex: 1, endColumnIndex: 4 }, cell: { userEnteredFormat: { horizontalAlignment: 'RIGHT' } }, fields: 'userEnteredFormat.horizontalAlignment' } });
req.push({ repeatCell: { range: { sheetId: SHEET_ID, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: 4 }, cell: { userEnteredFormat: { textFormat: { bold: true, fontSize: 13 } } }, fields: 'userEnteredFormat.textFormat' } });
sec.forEach((i, k) => req.push(band(i, cols[k], true, true)));
hdr.forEach((i) => req.push(band(i, grey, true, false)));
sub.forEach((i) => req.push({ repeatCell: { range: { sheetId: SHEET_ID, startRowIndex: i, endRowIndex: i + 1, startColumnIndex: 0, endColumnIndex: 4 }, cell: { userEnteredFormat: { textFormat: { bold: true } } }, fields: 'userEnteredFormat.textFormat' } }));
req.push({ updateSheetProperties: { properties: { sheetId: SHEET_ID, gridProperties: { frozenRowCount: 1 } }, fields: 'gridProperties.frozenRowCount' } });
req.push({ updateDimensionProperties: { range: { sheetId: SHEET_ID, dimension: 'COLUMNS', startIndex: 0, endIndex: 1 }, properties: { pixelSize: 240 }, fields: 'pixelSize' } });
req.push({ updateDimensionProperties: { range: { sheetId: SHEET_ID, dimension: 'COLUMNS', startIndex: 1, endIndex: 4 }, properties: { pixelSize: 95 }, fields: 'pixelSize' } });
return [{ json: { values: rows, requests: req } }];

const gscRows = ($('GSC 查詢').first().json.rows) || [];
const clicks = gscRows.reduce((s, r) => s + (r.clicks || 0), 0);
const impr = gscRows.reduce((s, r) => s + (r.impressions || 0), 0);
const pos = gscRows.length ? gscRows.reduce((s, r) => s + (r.position || 0), 0) / gscRows.length : 0;
const gaRows = ($('GA4 查詢').first().json.rows) || [];
const gn = (g, i) => Number((g.metricValues && g.metricValues[i]) ? g.metricValues[i].value : 0);
const sess = gaRows.reduce((s, g) => s + gn(g, 0), 0);
const users = gaRows.reduce((s, g) => s + gn(g, 1), 0);
const views = gaRows.reduce((s, g) => s + gn(g, 2), 0);
const th = ($('Threads 粉絲').first().json.data) || [];
const tm = (n) => { const m = th.find((d) => d.name === n); if (!m) return 0; if (m.total_value && m.total_value.value != null) return Number(m.total_value.value); if (Array.isArray(m.values)) return m.values.reduce((s, v) => s + Number(v.value || 0), 0); return 0; };
const followers = tm('followers_count');
const thViews = tm('views');
const thEng = tm('likes') + tm('replies') + tm('reposts') + tm('quotes');
const end = $today.minus({ days: 1 }).toFormat('yyyy-MM-dd');
const start = $today.minus({ days: 7 }).toFormat('yyyy-MM-dd');
const weekLabel = `${start} – ${end}`;
const labels = ['指標', '搜尋點擊', '搜尋曝光', '平均排名', '造訪次數', '訪客人數', '瀏覽頁數', '脆粉絲', '脆瀏覽', '脆互動'];
const vals = [weekLabel, clicks, impr, Number(pos.toFixed(1)), sess, users, views, followers, thViews, thEng];
const readJson = $('讀趨勢').first().json || {};
const row1 = ((readJson.values) || [])[0] || [];
const existing = row1.slice(1);
const idx = existing.indexOf(weekLabel);
const colIndex = idx >= 0 ? (1 + idx) : (1 + existing.length);
const colToA1 = (n) => { let s = ''; n++; while (n > 0) { const m = (n - 1) % 26; s = String.fromCharCode(65 + m) + s; n = Math.floor((n - 1) / 26); } return s; };
const colLetter = colToA1(colIndex);
return [{ json: { labelsRange: '趨勢!A1', labelsValues: labels.map((x) => [x]), weekRange: `趨勢!${colLetter}1`, weekValues: vals.map((x) => [x]) } }];
